#!/usr/bin/env python3
"""
deploy.py — Build/Install/Push for SubtitleBurner v1.1
Double-click to run.
"""

import base64, json, os, shutil, stat, subprocess, sys
import tempfile, time, traceback, urllib.request, urllib.error
from pathlib import Path

REPO_OWNER   = "granterogers"
REPO_NAME    = "SubtitleBurner"
INSTALL_DIR  = Path(r"C:\Users\grant.rogers\My Apps\SubtitleBurner")
TOKEN_FILE   = Path(r"C:\Users\grant.rogers\My Apps\_claude_config.txt")
PROCESS_NAME = "SubtitleBurner.exe"

PACKAGE_JSON = """
{
  "name": "subtitle-burner",
  "version": "1.1.0",
  "description": "Burn subtitles into MKV/MP4 with real-time preview",
  "main": "main.js",
  "scripts": {
    "start": "electron .",
    "build": "electron-builder --win portable --x64"
  },
  "build": {
    "appId": "com.granterogers.subtitleburner",
    "productName": "SubtitleBurner",
    "win": {
      "target": [{ "target": "portable", "arch": ["x64"] }]
    },
    "files": ["main.js", "renderer/**/*"],
    "portable": {
      "artifactName": "SubtitleBurner.exe"
    }
  },
  "devDependencies": {
    "electron": "^31.0.0",
    "electron-builder": "^25.0.0"
  }
}
"""

_MAIN_JS_B64      = ""
_PRELOAD_JS_B64   = ""
_INDEX_HTML_B64   = ""
_APP_JS_B64       = ""


def step(msg):  print("  ► " + msg)
def ok(msg):    print("  ✓ " + msg)

def read_token():
    if not TOKEN_FILE.exists():
        raise FileNotFoundError(f"Token file not found: {TOKEN_FILE}")
    for line in TOKEN_FILE.read_text().splitlines():
        if line.startswith("GITHUB_TOKEN="):
            return line.split("=", 1)[1].strip()
    raise ValueError("GITHUB_TOKEN= not found in token file")

def force_remove(path):
    def on_err(func, p, _):
        os.chmod(p, stat.S_IWRITE); func(p)
    if path.exists():
        shutil.rmtree(path, onerror=on_err)

def run(cmd, cwd=None, check=True):
    r = subprocess.run(cmd, cwd=cwd, capture_output=True, text=True)
    if check and r.returncode != 0:
        raise RuntimeError(r.stderr[-2000:] or r.stdout[-2000:])
    return r

def gh(method, endpoint, token, data=None):
    url = f"https://api.github.com{endpoint}"
    body = json.dumps(data).encode() if data else None
    req = urllib.request.Request(url, data=body, method=method, headers={
        "Authorization": f"token {token}",
        "Accept": "application/vnd.github+json",
        "Content-Type": "application/json",
        "User-Agent": "SubtitleBurner-deploy"
    })
    try:
        with urllib.request.urlopen(req) as r:
            return json.loads(r.read())
    except urllib.error.HTTPError as e:
        raise RuntimeError(f"{e.code}: {e.read().decode()}")

def push_file(path, content_bytes, token, msg):
    try:
        existing = gh("GET", f"/repos/{REPO_OWNER}/{REPO_NAME}/contents/{path}", token)
        sha = existing.get("sha")
    except RuntimeError as e:
        if "404" not in str(e): raise
        sha = None
    data = {"message": msg, "content": base64.b64encode(content_bytes).decode()}
    if sha: data["sha"] = sha
    gh("PUT", f"/repos/{REPO_OWNER}/{REPO_NAME}/contents/{path}", token, data)
    ok(f"  {path}")


def find_npm():
    """Find npm executable, handling Windows PATH quirks."""
    import shutil
    # 1. Simple PATH lookup
    found = shutil.which("npm")
    if found:
        return found
    # 2. Common Windows install locations
    candidates = [
        Path(os.environ.get("APPDATA", ""), "npm", "npm.cmd"),
        Path(os.environ.get("ProgramFiles", r"C:\Program Files"), "nodejs", "npm.cmd"),
        Path(os.environ.get("ProgramFiles(x86)", r"C:\Program Files (x86)"), "nodejs", "npm.cmd"),
        Path(os.environ.get("LOCALAPPDATA", ""), "Programs", "nodejs", "npm.cmd"),
        Path(r"C:\Program Files\nodejs\npm.cmd"),
        Path(r"C:\Program Files (x86)\nodejs\npm.cmd"),
    ]
    for c in candidates:
        if c.exists():
            return str(c)
    raise FileNotFoundError(
        "npm not found. Please install Node.js from https://nodejs.org and restart."
    )


def find_electron(install_dir):
    """Find the electron binary inside the local node_modules."""
    # Prefer local node_modules/.bin/electron (installed by npm install)
    candidates = [
        install_dir / "node_modules" / ".bin" / "electron.cmd",
        install_dir / "node_modules" / ".bin" / "electron",
    ]
    for c in candidates:
        if Path(c).exists():
            return str(c)
    # Fall back to global npx / electron
    import shutil
    for name in ["electron.cmd", "electron"]:
        found = shutil.which(name)
        if found:
            return found
    raise FileNotFoundError(
        "electron binary not found. Try running npm install in the install directory."
    )

def main():
    print()
    print("=" * 60)
    print("  SubtitleBurner Deploy v1.1")
    print("=" * 60)
    print()

    tmp = Path(tempfile.mkdtemp(prefix="sbt_deploy_"))
    try:
        step("Writing source files...")
        src = tmp / "src"
        src.mkdir()
        (src / "package.json").write_text(PACKAGE_JSON)
        (src / "main.js").write_bytes(base64.b64decode(_MAIN_JS_B64))
        (src / "renderer").mkdir()
        (src / "renderer" / "preload.js").write_bytes(base64.b64decode(_PRELOAD_JS_B64))
        (src / "renderer" / "index.html").write_bytes(base64.b64decode(_INDEX_HTML_B64))
        (src / "renderer" / "app.js").write_bytes(base64.b64decode(_APP_JS_B64))
        ok("Source files written")

        step("Stopping any running instance...")
        run(["taskkill", "/F", "/IM", PROCESS_NAME], check=False)
        time.sleep(1)
        ok("Done")

        step(f"Installing to {INSTALL_DIR}...")
        force_remove(INSTALL_DIR)
        INSTALL_DIR.mkdir(parents=True, exist_ok=True)
        (INSTALL_DIR / "renderer").mkdir()
        for f in ["package.json", "main.js"]:
            shutil.copy(src / f, INSTALL_DIR / f)
        for f in ["preload.js", "index.html", "app.js"]:
            shutil.copy(src / "renderer" / f, INSTALL_DIR / "renderer" / f)
        ok("Files copied")

        step("Running npm install...")
        npm = find_npm()
        run([npm, "install"], cwd=str(INSTALL_DIR))
        ok("npm install complete")

        step("Launching app...")
        electron = find_electron(INSTALL_DIR)
        subprocess.Popen(
            [electron, "."],
            cwd=str(INSTALL_DIR),
            creationflags=subprocess.CREATE_NO_WINDOW if sys.platform == "win32" else 0
        )
        ok("Launched.")

        print()
        if input("  Push source to GitHub? (Y/N): ").strip().upper() != "Y":
            print("  Skipped.")
            return

        step("Reading GitHub token...")
        token = read_token()
        ok("Token loaded.")

        try:
            gh("GET", f"/repos/{REPO_OWNER}/{REPO_NAME}", token)
            ok("Repo exists.")
        except RuntimeError as e:
            if "404" not in str(e): raise
            step("Creating repo...")
            gh("POST", "/user/repos", token, {
                "name": REPO_NAME, "private": False, "auto_init": False,
                "description": "Electron subtitle burner with real-time preview"
            })
            ok("Repo created.")

        step("Pushing files...")
        msg = f"deploy: {time.strftime('%Y-%m-%d %H:%M')}"
        push_file("package.json",        PACKAGE_JSON.encode(),             token, msg)
        push_file("main.js",             base64.b64decode(_MAIN_JS_B64),    token, msg)
        push_file("renderer/preload.js", base64.b64decode(_PRELOAD_JS_B64), token, msg)
        push_file("renderer/index.html", base64.b64decode(_INDEX_HTML_B64), token, msg)
        push_file("renderer/app.js",     base64.b64decode(_APP_JS_B64),     token, msg)
        push_file("deploy.py",           Path(__file__).read_bytes(),       token, msg)
        ok(f"All pushed → https://github.com/{REPO_OWNER}/{REPO_NAME}")

    finally:
        step("Cleaning up...")
        force_remove(tmp)
        ok("Done.")


if __name__ == "__main__":
    try:
        main()
    except Exception:
        print("\n" + "!" * 60)
        traceback.print_exc()
        print("!" * 60)
    input("\nPress Enter to exit...")
